"use client";

import { useRef, useEffect } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import Link from "next/link";
import { ArrowRight, Sparkles } from "lucide-react";
import FloatingScene from "@/components/3d/FloatingScene";
import { content } from "@/lib/siteConfig";

if (typeof window !== "undefined") {
    gsap.registerPlugin(ScrollTrigger);
}

export default function HeroSection() {
    const sectionRef = useRef<HTMLDivElement>(null);
    const headlineRef = useRef<HTMLHeadingElement>(null);
    const subheadRef = useRef<HTMLParagraphElement>(null);
    const ctaRef = useRef<HTMLDivElement>(null);

    const { scrollYProgress } = useScroll({
        target: sectionRef,
        offset: ["start start", "end start"],
    });

    // Parallax transforms
    const y = useTransform(scrollYProgress, [0, 1], ["0%", "50%"]);
    const opacity = useTransform(scrollYProgress, [0, 0.5], [1, 0]);
    const scale = useTransform(scrollYProgress, [0, 1], [1, 0.8]);

    useEffect(() => {
        const ctx = gsap.context(() => {
            // Animate headline letters
            const headline = headlineRef.current;
            if (headline) {
                const chars = headline.innerText.split("");
                headline.innerHTML = chars
                    .map((char) => `<span class="inline-block">${char === " " ? "&nbsp;" : char}</span>`)
                    .join("");

                gsap.fromTo(
                    headline.querySelectorAll("span"),
                    {
                        opacity: 0,
                        y: 100,
                        rotateX: -90,
                    },
                    {
                        opacity: 1,
                        y: 0,
                        rotateX: 0,
                        duration: 1,
                        stagger: 0.05,
                        ease: "expo.out",
                        delay: 0.3,
                    }
                );
            }

            // Animate subheadline
            gsap.fromTo(
                subheadRef.current,
                { opacity: 0, y: 40 },
                { opacity: 1, y: 0, duration: 0.8, ease: "expo.out", delay: 0.8 }
            );

            // Animate CTAs
            gsap.fromTo(
                ctaRef.current,
                { opacity: 0, y: 40 },
                { opacity: 1, y: 0, duration: 0.8, ease: "expo.out", delay: 1 }
            );
        }, sectionRef);

        return () => ctx.revert();
    }, []);

    return (
        <section
            ref={sectionRef}
            className="relative min-h-screen flex items-center justify-center overflow-hidden"
        >
            {/* 3D Background Scene */}
            <motion.div style={{ y, scale }} className="absolute inset-0">
                <FloatingScene />
            </motion.div>

            {/* Gradient Overlay */}
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-[#050A14]/50 to-[#050A14] pointer-events-none" />

            {/* Animated background orbs */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none">
                <motion.div
                    className="absolute top-1/4 -left-32 w-96 h-96 rounded-full"
                    style={{
                        background: "radial-gradient(circle, rgba(0, 240, 255, 0.3) 0%, transparent 70%)",
                        filter: "blur(60px)",
                    }}
                    animate={{
                        x: [0, 50, 0],
                        y: [0, 30, 0],
                        scale: [1, 1.2, 1],
                    }}
                    transition={{
                        duration: 8,
                        repeat: Infinity,
                        ease: "easeInOut",
                    }}
                />
                <motion.div
                    className="absolute bottom-1/4 -right-32 w-96 h-96 rounded-full"
                    style={{
                        background: "radial-gradient(circle, rgba(255, 0, 255, 0.3) 0%, transparent 70%)",
                        filter: "blur(60px)",
                    }}
                    animate={{
                        x: [0, -50, 0],
                        y: [0, -30, 0],
                        scale: [1, 1.2, 1],
                    }}
                    transition={{
                        duration: 10,
                        repeat: Infinity,
                        ease: "easeInOut",
                    }}
                />
            </div>

            {/* Content */}
            <motion.div style={{ opacity }} className="relative z-10 container-custom pt-32">
                <div className="max-w-5xl mx-auto text-center">
                    {/* Badge */}
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6, delay: 0.1 }}
                        className="inline-flex items-center gap-2 px-4 py-2 rounded-full glass mb-8"
                    >
                        <Sparkles className="w-4 h-4 text-[#00F0FF]" />
                        <span className="text-sm text-white/80">Next-Gen AI Solutions</span>
                    </motion.div>

                    {/* Main Headline */}
                    <h1
                        ref={headlineRef}
                        className="text-6xl sm:text-7xl md:text-8xl lg:text-9xl font-bold mb-6 tracking-tighter"
                    >
                        <span className="text-gradient">{content.hero.headline}</span>
                    </h1>

                    {/* Subheadline */}
                    <p
                        ref={subheadRef}
                        className="text-xl sm:text-2xl md:text-3xl text-white/80 mb-8 max-w-3xl mx-auto leading-relaxed"
                    >
                        {content.hero.subheadline}
                    </p>

                    {/* Description */}
                    <motion.p
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.9 }}
                        className="text-base sm:text-lg text-white/60 mb-12 max-w-2xl mx-auto"
                    >
                        {content.hero.description}
                    </motion.p>

                    {/* CTA Buttons */}
                    <div ref={ctaRef} className="flex flex-col sm:flex-row items-center justify-center gap-4">
                        <Link href="/contact">
                            <motion.button
                                className="group relative px-8 py-4 bg-[#00F0FF] text-black font-bold rounded-full overflow-hidden"
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.95 }}
                            >
                                <span className="relative z-10 flex items-center gap-2">
                                    {content.hero.cta.primary}
                                    <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                                </span>
                                <motion.div
                                    className="absolute inset-0 bg-white"
                                    initial={{ x: "-100%" }}
                                    whileHover={{ x: 0 }}
                                    transition={{ duration: 0.3 }}
                                />
                            </motion.button>
                        </Link>

                        <Link href="/services">
                            <motion.button
                                className="group px-8 py-4 border border-white/20 text-white font-medium rounded-full hover:border-[#00F0FF]/50 transition-colors"
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.95 }}
                            >
                                {content.hero.cta.secondary}
                            </motion.button>
                        </Link>
                    </div>
                </div>

                {/* Scroll Indicator */}
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ delay: 1.5 }}
                    className="absolute bottom-12 left-1/2 -translate-x-1/2"
                >
                    <motion.div
                        className="w-6 h-10 rounded-full border-2 border-white/30 flex items-start justify-center p-2"
                        animate={{ y: [0, 10, 0] }}
                        transition={{ duration: 1.5, repeat: Infinity }}
                    >
                        <motion.div
                            className="w-1.5 h-1.5 rounded-full bg-[#00F0FF]"
                            animate={{ y: [0, 12, 0], opacity: [1, 0.3, 1] }}
                            transition={{ duration: 1.5, repeat: Infinity }}
                        />
                    </motion.div>
                </motion.div>
            </motion.div>
        </section>
    );
}
