"use client";

import { useRef, useEffect } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Zap, Brain, Rocket } from "lucide-react";

const features = [
    {
        icon: Brain,
        title: "AI-Powered Intelligence",
        description: "Leverage cutting-edge machine learning models that adapt and evolve with your business needs.",
        color: "#00F0FF",
    },
    {
        icon: Zap,
        title: "Lightning Performance",
        description: "Optimized architectures delivering sub-second response times at enterprise scale.",
        color: "#FF00FF",
    },
    {
        icon: Rocket,
        title: "Future-Ready Infrastructure",
        description: "Cloud-native solutions built for tomorrow's challenges, today.",
        color: "#8B5CF6",
    },
];

export default function TransformationSection() {
    const sectionRef = useRef<HTMLDivElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);

    const { scrollYProgress } = useScroll({
        target: sectionRef,
        offset: ["start end", "end start"],
    });

    const y = useTransform(scrollYProgress, [0, 1], ["0%", "30%"]);
    const opacity = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [0, 1, 1, 0]);

    useEffect(() => {
        const ctx = gsap.context(() => {
            // Animate feature cards
            gsap.fromTo(
                ".feature-card",
                {
                    opacity: 0,
                    y: 60,
                    scale: 0.9,
                },
                {
                    opacity: 1,
                    y: 0,
                    scale: 1,
                    duration: 0.8,
                    stagger: 0.2,
                    ease: "expo.out",
                    scrollTrigger: {
                        trigger: containerRef.current,
                        start: "top 80%",
                        end: "top 20%",
                        toggleActions: "play none none reverse",
                    },
                }
            );
        }, sectionRef);

        return () => ctx.revert();
    }, []);

    return (
        <section
            ref={sectionRef}
            className="relative min-h-screen py-32 overflow-hidden"
        >
            {/* Background Elements */}
            <div className="absolute inset-0 gradient-mesh" />

            {/* Animated Grid */}
            <div className="absolute inset-0 opacity-20">
                <div
                    className="absolute inset-0"
                    style={{
                        backgroundImage: `
              linear-gradient(rgba(0, 240, 255, 0.1) 1px, transparent 1px),
              linear-gradient(90deg, rgba(0, 240, 255, 0.1) 1px, transparent 1px)
            `,
                        backgroundSize: "50px 50px",
                    }}
                />
            </div>

            <motion.div style={{ opacity }} className="relative z-10 container-custom">
                {/* Section Header */}
                <div className="text-center mb-20">
                    <motion.span
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        className="inline-block px-4 py-2 rounded-full glass text-[#00F0FF] text-sm font-medium mb-6"
                    >
                        Our Approach
                    </motion.span>
                    <motion.h2
                        initial={{ opacity: 0, y: 30 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ delay: 0.1 }}
                        className="text-4xl sm:text-5xl md:text-6xl font-bold mb-6"
                    >
                        Transforming Ideas into
                        <br />
                        <span className="text-gradient">Digital Reality</span>
                    </motion.h2>
                    <motion.p
                        initial={{ opacity: 0, y: 30 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ delay: 0.2 }}
                        className="text-lg text-white/60 max-w-2xl mx-auto"
                    >
                        We combine innovative technology with strategic thinking to deliver
                        solutions that drive real business impact.
                    </motion.p>
                </div>

                {/* Feature Cards */}
                <div ref={containerRef} className="grid md:grid-cols-3 gap-8">
                    {features.map((feature, index) => (
                        <motion.div
                            key={feature.title}
                            className="feature-card group relative p-8 rounded-2xl glass hover:bg-white/10 transition-all duration-500"
                            whileHover={{ y: -10, scale: 1.02 }}
                            transition={{ type: "spring", stiffness: 300 }}
                        >
                            {/* Glow Effect */}
                            <div
                                className="absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-500 blur-xl"
                                style={{
                                    background: `radial-gradient(circle at center, ${feature.color}20 0%, transparent 70%)`,
                                }}
                            />

                            {/* Border Glow */}
                            <div
                                className="absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-500"
                                style={{
                                    border: `1px solid ${feature.color}50`,
                                }}
                            />

                            <div className="relative z-10">
                                {/* Icon */}
                                <div
                                    className="w-14 h-14 rounded-xl flex items-center justify-center mb-6"
                                    style={{ backgroundColor: `${feature.color}20` }}
                                >
                                    <feature.icon
                                        className="w-7 h-7"
                                        style={{ color: feature.color }}
                                    />
                                </div>

                                {/* Content */}
                                <h3 className="text-xl font-bold mb-3 group-hover:text-white transition-colors">
                                    {feature.title}
                                </h3>
                                <p className="text-white/60 leading-relaxed">
                                    {feature.description}
                                </p>
                            </div>

                            {/* Number */}
                            <div className="absolute top-6 right-6 text-6xl font-bold text-white/5">
                                0{index + 1}
                            </div>
                        </motion.div>
                    ))}
                </div>

                {/* Stats Row */}
                <motion.div
                    initial={{ opacity: 0, y: 40 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.4 }}
                    className="mt-20 grid grid-cols-2 md:grid-cols-4 gap-8"
                >
                    {[
                        { value: "500+", label: "Projects Delivered" },
                        { value: "98%", label: "Client Satisfaction" },
                        { value: "150+", label: "AI Solutions" },
                        { value: "12", label: "Years Experience" },
                    ].map((stat, index) => (
                        <div key={stat.label} className="text-center">
                            <div className="text-4xl sm:text-5xl font-bold text-gradient mb-2">
                                {stat.value}
                            </div>
                            <div className="text-sm text-white/50">{stat.label}</div>
                        </div>
                    ))}
                </motion.div>
            </motion.div>
        </section>
    );
}
